C  fftfort.fC=====================================================================C         C     SUBROUTINE FFTC PERFORMS DISCRETE FOURIER TRANSFORM BY          C         C     RADIX-4 COMPLEX FFT ALGORITHM                                   C         C     USAGE: CALL FFTC(A,M,INV,ILL)                                   C         C          A......1-DIMENSIONAL COMPLEX ARRAY OF SIZE 2**M            C         C                 INPUT....DATA TO BE TRANSORMED                      C         C                 OUTPUT...TRANSFORMED DATA                           C         C          M......INTEGER INPUT...BASE 2 LOGARITHM OF DATA SIZE       C         C          INV....INTEGER INPUT...0: FORWAED TRANSFORMATION           C         C                              ...1: INVERSE TRANSFORMATION           C         C                 (DIVIDE BY N=2**M TO OBTAIN THE TRUE INVERSE)       C         C          ILL....INTEGER OUTPUT..ERROR CODE 0: NORMAL TERMINATION    C         C                                            30000: PARAMETER ERROR   C         C     SLAVE ROUTINE: BITRVC(NUMPAC) FOR BIT REVERSAL REARRANGEMENT    C         C     AUTHOR: I.NINOMIYA (CHUBU UNIVERSITY,KASUGAI,AICHI JAPAN 487)   C         C     DATA OF CREATION:  1981-04-01                                   C         C=====================================================================C         C---------------------------------------------------------------------C               SUBROUTINE FFTC(A,M,INV,ILL)                                              C---------------------------------------------------------------------C               DOUBLE PRECISION DC,DS,CC,SS,CO,SO,CN,SN,PP                                     DIMENSION A(*),DC(32),DS(32)                                              C---------------------------------------------------------------------C         C     DC(I)=COS(PI/2**(I+1)) DS(I)=SIN(PI/2**(I+1))                             C---------------------------------------------------------------------C               DATA DC( 1)/ 0.707106781186547531D+00/                                          DATA DC( 2)/ 0.923879532511286752D+00/                                          DATA DC( 3)/ 0.980785280403230444D+00/                                          DATA DC( 4)/ 0.995184726672196887D+00/                                          DATA DC( 5)/ 0.998795456205172391D+00/                                          DATA DC( 6)/ 0.999698818696204222D+00/                                          DATA DC( 7)/ 0.999924701839144545D+00/                                          DATA DC( 8)/ 0.999981175282601137D+00/                                          DATA DC( 9)/ 0.999995293809576177D+00/                                          DATA DC(10)/ 0.999998823451701907D+00/                                          DATA DC(11)/ 0.999999705862882213D+00/                                          DATA DC(12)/ 0.999999926465717850D+00/                                          DATA DC(13)/ 0.999999981616429293D+00/                                          DATA DC(14)/ 0.999999995404107320D+00/                                          DATA DC(15)/ 0.999999998851026833D+00/                                          DATA DC(16)/ 0.999999999712756701D+00/                                          DATA DC(17)/ 0.999999999928189179D+00/                                          DATA DC(18)/ 0.999999999982047291D+00/                                          DATA DC(19)/ 0.999999999995511826D+00/                                          DATA DC(20)/ 0.999999999998877953D+00/                                          DATA DC(21)/ 0.999999999999719488D+00/                                          DATA DC(22)/ 0.999999999999929876D+00/                                          DATA DC(23)/ 0.999999999999982472D+00/                                          DATA DC(24)/ 0.999999999999995615D+00/                                          DATA DC(25)/ 0.999999999999998904D+00/                                          DATA DC(26)/ 0.999999999999999722D+00/                                          DATA DC(27)/ 0.999999999999999931D+00/                                          DATA DC(28)/ 0.999999999999999986D+00/                                          DATA DC(29)/ 0.100000000000000000D+01/                                          DATA DC(30)/ 0.100000000000000000D+01/                                          DATA DC(31)/ 0.100000000000000000D+01/                                          DATA DC(32)/ 0.100000000000000000D+01/                                          DATA DS( 1)/ 0.707106781186547531D+00/                                          DATA DS( 2)/ 0.382683432365089768D+00/                                          DATA DS( 3)/ 0.195090322016128262D+00/                                          DATA DS( 4)/ 0.980171403295606036D-01/                                          DATA DS( 5)/ 0.490676743274180141D-01/                                          DATA DS( 6)/ 0.245412285229122881D-01/                                          DATA DS( 7)/ 0.122715382857199263D-01/                                          DATA DS( 8)/ 0.613588464915447527D-02/                                          DATA DS( 9)/ 0.306795676296597625D-02/                                          DATA DS(10)/ 0.153398018628476561D-02/                                          DATA DS(11)/ 0.766990318742704540D-03/                                          DATA DS(12)/ 0.383495187571395563D-03/                                          DATA DS(13)/ 0.191747597310703308D-03/                                          DATA DS(14)/ 0.958737990959773447D-04/                                          DATA DS(15)/ 0.479368996030668847D-04/                                          DATA DS(16)/ 0.239684498084182193D-04/                                          DATA DS(17)/ 0.119842249050697064D-04/                                          DATA DS(18)/ 0.599211245264242774D-05/                                          DATA DS(19)/ 0.299605622633466084D-05/                                          DATA DS(20)/ 0.149802811316901114D-05/                                          DATA DS(21)/ 0.749014056584715715D-06/                                          DATA DS(22)/ 0.374507028292384129D-06/                                          DATA DS(23)/ 0.187253514146195347D-06/                                          DATA DS(24)/ 0.936267570730980836D-07/                                          DATA DS(25)/ 0.468133785365490931D-07/                                          DATA DS(26)/ 0.234066892682745532D-07/                                          DATA DS(27)/ 0.117033446341372770D-07/                                          DATA DS(28)/ 0.585167231706863850D-08/                                          DATA DS(29)/ 0.292583615853431935D-08/                                          DATA DS(30)/ 0.146291807926715968D-08/                                          DATA DS(31)/ 0.731459039633579864D-09/                                          DATA DS(32)/ 0.365729519816789906D-09/                                    C---------------------------------------------------------------------C               IF(M.LT.0) GO TO 70                                                             NN=2**(M+1)                                                                     L=NN                                                                            G=INV+INV-1                                                                     DO 40 I=2,M,2                                                                   L4=L/4                                                                          DO 10 K0=2,NN,L                                                                 K2=K0+L4                                                                        K1=K2+L4                                                                        K3=K1+L4                                                                        T1=A(K0-1)+A(K1-1)                                                              U1=A(K0-1)-A(K1-1)                                                              T2=A(K0)+A(K1)                                                                  U2=A(K0)-A(K1)                                                                  V1=A(K2-1)+A(K3-1)                                                              W2=(A(K2-1)-A(K3-1))*G                                                          V2=A(K2)+A(K3)                                                                  W1=(A(K3)-A(K2))*G                                                              A(K0-1)=T1+V1                                                                   A(K0)=T2+V2                                                                     A(K2-1)=T1-V1                                                                   A(K2)=T2-V2                                                                     A(K1-1)=U1+W1                                                                   A(K1)=U2+W2                                                                     A(K3-1)=U1-W1                                                                10 A(K3)=U2-W2                                                                     IF(L4.LT.4) GO TO 40                                                            CC=DC(M-I)                                                                      SS=DS(M-I)*G                                                                    PP=SS+SS                                                                        CO=1.D0                                                                         SO=0.D0                                                                         DO 30 J=4,L4,2                                                                  C1=CC                                                                           S1=SS                                                                           P=S1+S1                                                                         C2=(C1-S1)*(C1+S1)                                                              S2=C1*P                                                                         C3=C1-P*S2                                                                      S3=P*C2+S1                                                                      DO 20 K0=J,NN,L                                                                 K2=K0+L4                                                                        K1=K2+L4                                                                        K3=K1+L4                                                                        T1=A(K0-1)+A(K1-1)                                                              U1=A(K0-1)-A(K1-1)                                                              T2=A(K0)+A(K1)                                                                  U2=A(K0)-A(K1)                                                                  V1=A(K2-1)+A(K3-1)                                                              W2=(A(K2-1)-A(K3-1))*G                                                          V2=A(K2)+A(K3)                                                                  W1=(A(K3)-A(K2))*G                                                              A(K0-1)=T1+V1                                                                   A(K0)=T2+V2                                                                     TV1=T1-V1                                                                       TV2=T2-V2                                                                       A(K2-1)=TV1*C2-TV2*S2                                                           A(K2)=TV1*S2+TV2*C2                                                             UW1=U1+W1                                                                       UW2=U2+W2                                                                       A(K1-1)=UW1*C1-UW2*S1                                                           A(K1)=UW1*S1+UW2*C1                                                             UW1=U1-W1                                                                       UW2=U2-W2                                                                       A(K3-1)=UW1*C3-UW2*S3                                                        20 A(K3)=UW1*S3+UW2*C3                                                             CN=CO-PP*SS                                                                     SN=PP*CC+SO                                                                     CO=CC                                                                           CC=CN                                                                           SO=SS                                                                        30 SS=SN                                                                        40 L=L4                                                                            IF(L.EQ.2) GO TO 60                                                             DO 50 K0=2,NN,4                                                                 T1=A(K0-1)                                                                      T2=A(K0)                                                                        A(K0-1)=T1+A(K0+1)                                                              A(K0)=T2+A(K0+2)                                                                A(K0+1)=T1-A(K0+1)                                                           50 A(K0+2)=T2-A(K0+2)                                                        C-------- CALL BIT REVERSAL SUBROUTINE -------------------------------C            60 CALL BITRVC(A,M,ILL)                                                            RETURN                                                                    C-------- ERROR HANDLING ---------------------------------------------C            70 ILL=30000                                                                       RETURN                                                                          END                                                                       C=====================================================================C         C     SUBROUTINE BITRVC/D PERFORMS BIT REVERSAL REARRANGEMENT OF      C         C     REAL ARRAY OF SIZE OF THE FORM 2**L                             C         C     USAGE: CALL BITRVC(A,L,ILL)                                     C         C          A......1-DIMENSIONAL COMPLEX/DOUBLE ARRAY OF SIZE 2**L     C         C                 INPUT....DATA TO BE REARRANGED                      C         C                 OUTPUT...REARRANGED DATA                            C         C          L......INTEGER INPUT...BASE 2 LOGARITHM OF DATA SIZE       C         C          ILL....INTEGER OUTPUT..ERROR CODE 0: NORMAL TERMINATION    C         C                                            30000: PARAMETER ERROR   C         C     AUTHOR: I.NINOMIYA (CHUBU UNIVERSITY,KASUGAI,AICHI JAPAN 487)   C         C     DATA OF CREATION:  1981-04-01                                   C         C=====================================================================C         C---------------------------------------------------------------------C               SUBROUTINE BITRVC(A,L,ICON)                                               C---------------------------------------------------------------------C               COMPLEX A(*),W                                                                  DIMENSION ITEST(20),INC(20)                                               C---------------------------------------------------------------------C               IF(L.LE.0.OR.L.GT.23) GO TO 8000                                                NN=0                                                                            NR=0                                                                            I=L-1                                                                           M=2**I                                                                          K=2                                                                             IF(I-2) 60,30,10                                                             10 I=I-1                                                                           ITEST(I-1)=M-K                                                                  K=K+K                                                                           INC(I-1)=K-ITEST(I-1)                                                           IF(I-3) 30,10,10                                                          C---------------------------------------------------------------------C            20 NR=INC(I)+NR                                                                 30 MR=M+NR                                                                         IF(NR-NN) 50,50,40                                                           40 W=A(NN+1)                                                                       A(NN+1)=A(NR+1)                                                                 A(NR+1)=W                                                                       MN=M+NN                                                                         W=A(MN+2)                                                                       A(MN+2)=A(MR+2)                                                                 A(MR+2)=W                                                                    50 NN=NN+2                                                                         W=A(NN)                                                                         A(NN)=A(MR+1)                                                                   A(MR+1)=W                                                                       NR=K+NR                                                                      60 MR=M+NR                                                                         IF(NR-NN) 80,80,70                                                           70 W=A(NN+1)                                                                       A(NN+1)=A(NR+1)                                                                 A(NR+1)=W                                                                       MN=M+NN                                                                         W=A(MN+2)                                                                       A(MN+2)=A(MR+2)                                                                 A(MR+2)=W                                                                    80 NN=NN+2                                                                         W=A(NN)                                                                         A(NN)=A(MR+1)                                                                   A(MR+1)=W                                                                       I=1                                                                             IF(NN-M) 100,110,110                                                         90 I=I+1                                                                       100 IF(NR-ITEST(I)) 20,90,90                                                  C---------------------------------------------------------------------C           110 ICON=0                                                                          RETURN                                                                    C---------------------------------------------------------------------C          8000 ICON=30000                                                                      RETURN                                                                          END                                                                       C=====================================================================C         C     SUBROUTINE FFTR PERFORMS DISCRETE FOURIER ANALYSIS BY           C         C     RADIX-2 REAL FFT ALGORITHM                                      C         C     USAGE: CALL FFTR(A,M,ILL)                                       C         C          A......1-DIMENSIONAL REAL ARRAY OF SIZE 2**M               C         C                 INPUT....DATA TO BE ANALYZED                        C         C                 OUTPUT...ANALYZED DATA                              C         C                          K-TH COSINE COMPONENT IN A(K+1)            C         C                          K-TH SINE COMPONENT IN A(N/2+K+1),N=2**M   C         C          M......INTEGER INPUT...BASE 2 LOGARITHM OF DATA SIZE       C         C          ILL....INTEGER OUTPUT..ERROR CODE 0: NORMAL TERMINATION    C         C                                            30000: PARAMETER ERROR   C         C     SLAVE ROUTINE: BITREV(NUMPAC) FOR BIT REVERSAL REARRANGEMENT    C         C     AUTHOR: I.NINOMIYA (CHUBU UNIVERSITY,KASUGAI,AICHI JAPAN 487)   C         C     DATA OF CREATION:  1981-04-01                                   C         C=====================================================================C         C---------------------------------------------------------------------C               SUBROUTINE FFTR(A,M,ILL)                                                  C---------------------------------------------------------------------C               DIMENSION A(*)                                                                  DOUBLE PRECISION DC(32),DS(32),SS                                         C---------------------------------------------------------------------C         C     DC(I)=COS(PI/2**(I+1)),DS(I)=SIN(PI/2**(I+1))                             C---------------------------------------------------------------------C               DATA DC( 1)/ 0.707106781186547531D+00/                                          DATA DC( 2)/ 0.923879532511286752D+00/                                          DATA DC( 3)/ 0.980785280403230444D+00/                                          DATA DC( 4)/ 0.995184726672196887D+00/                                          DATA DC( 5)/ 0.998795456205172391D+00/                                          DATA DC( 6)/ 0.999698818696204222D+00/                                          DATA DC( 7)/ 0.999924701839144545D+00/                                          DATA DC( 8)/ 0.999981175282601137D+00/                                          DATA DC( 9)/ 0.999995293809576177D+00/                                          DATA DC(10)/ 0.999998823451701907D+00/                                          DATA DC(11)/ 0.999999705862882213D+00/                                          DATA DC(12)/ 0.999999926465717850D+00/                                          DATA DC(13)/ 0.999999981616429293D+00/                                          DATA DC(14)/ 0.999999995404107320D+00/                                          DATA DC(15)/ 0.999999998851026833D+00/                                          DATA DC(16)/ 0.999999999712756701D+00/                                          DATA DC(17)/ 0.999999999928189179D+00/                                          DATA DC(18)/ 0.999999999982047291D+00/                                          DATA DC(19)/ 0.999999999995511826D+00/                                          DATA DC(20)/ 0.999999999998877953D+00/                                          DATA DC(21)/ 0.999999999999719488D+00/                                          DATA DC(22)/ 0.999999999999929876D+00/                                          DATA DC(23)/ 0.999999999999982472D+00/                                          DATA DC(24)/ 0.999999999999995615D+00/                                          DATA DC(25)/ 0.999999999999998904D+00/                                          DATA DC(26)/ 0.999999999999999722D+00/                                          DATA DC(27)/ 0.999999999999999931D+00/                                          DATA DC(28)/ 0.999999999999999986D+00/                                          DATA DC(29)/ 0.100000000000000000D+01/                                          DATA DC(30)/ 0.100000000000000000D+01/                                          DATA DC(31)/ 0.100000000000000000D+01/                                          DATA DC(32)/ 0.100000000000000000D+01/                                          DATA DS( 1)/ 0.707106781186547531D+00/                                          DATA DS( 2)/ 0.382683432365089768D+00/                                          DATA DS( 3)/ 0.195090322016128262D+00/                                          DATA DS( 4)/ 0.980171403295606036D-01/                                          DATA DS( 5)/ 0.490676743274180141D-01/                                          DATA DS( 6)/ 0.245412285229122881D-01/                                          DATA DS( 7)/ 0.122715382857199263D-01/                                          DATA DS( 8)/ 0.613588464915447527D-02/                                          DATA DS( 9)/ 0.306795676296597625D-02/                                          DATA DS(10)/ 0.153398018628476561D-02/                                          DATA DS(11)/ 0.766990318742704540D-03/                                          DATA DS(12)/ 0.383495187571395563D-03/                                          DATA DS(13)/ 0.191747597310703308D-03/                                          DATA DS(14)/ 0.958737990959773447D-04/                                          DATA DS(15)/ 0.479368996030668847D-04/                                          DATA DS(16)/ 0.239684498084182193D-04/                                          DATA DS(17)/ 0.119842249050697064D-04/                                          DATA DS(18)/ 0.599211245264242774D-05/                                          DATA DS(19)/ 0.299605622633466084D-05/                                          DATA DS(20)/ 0.149802811316901114D-05/                                          DATA DS(21)/ 0.749014056584715715D-06/                                          DATA DS(22)/ 0.374507028292384129D-06/                                          DATA DS(23)/ 0.187253514146195347D-06/                                          DATA DS(24)/ 0.936267570730980836D-07/                                          DATA DS(25)/ 0.468133785365490931D-07/                                          DATA DS(26)/ 0.234066892682745532D-07/                                          DATA DS(27)/ 0.117033446341372770D-07/                                          DATA DS(28)/ 0.585167231706863850D-08/                                          DATA DS(29)/ 0.292583615853431935D-08/                                          DATA DS(30)/ 0.146291807926715968D-08/                                          DATA DS(31)/ 0.731459039633579864D-09/                                          DATA DS(32)/ 0.365729519816789906D-09/                                    C---------------------------------------------------------------------C               N2=1                                                                            IF(M.LE.0) GOTO 110                                                             IF(M.EQ.1) GOTO 90                                                        C---------------------------------------------------------------------C               CALL BITREV(A,M,ILL)                                                      C---------------------------------------------------------------------C               N=2**M                                                                          F=2.0/FLOAT(N)                                                                  DO 20 L=1,N,2                                                                   P=A(L+1)                                                                        A(L+1)=(A(L)-P)*F                                                            20 A(L)=(A(L)+P)*F                                                                 N1=1                                                                            N2=2                                                                            N3=4                                                                            N4=8                                                                            DO 70 I=1,M-2                                                                   DO 30 L=1,N,N3                                                                  L1=L+N2                                                                         P=A(L)                                                                          A(L)=P+A(L1)                                                                 30 A(L1)=P-A(L1)                                                                   C=DC(I)                                                                         S=DS(I)                                                                         SS=DS(I)+DS(I)                                                                  CO=1.0                                                                          SO=0.0                                                                          DO 50 K=1,N1-1                                                                  N3K=N3-K                                                                        N2K=N2-K                                                                        DO 40 J=1,N,N4                                                                  L0=J+K                                                                          L2=L0+N3                                                                        L1=J+N3K                                                                        L3=L1+N3                                                                        P=C*A(L2)-S*A(L3)                                                               Q=S*A(L2)+C*A(L3)                                                               A(L2)=Q-A(L1)                                                                   A(L3)=Q+A(L1)                                                                   A(L1)=A(L0)-P                                                                   A(L0)=A(L0)+P                                                                   L1=L0+N2                                                                        L3=L1+N3                                                                        L0=J+N2K                                                                        L2=L0+N3                                                                        P=A(L2)*S-A(L3)*C                                                               Q=A(L2)*C+A(L3)*S                                                               A(L2)=Q-A(L1)                                                                   A(L3)=Q+A(L1)                                                                   A(L1)=A(L0)-P                                                                   A(L0)=A(L0)+P                                                                40 CONTINUE                                                                        CN=CO-SS*S                                                                      SN=SS*C+SO                                                                      CO=C                                                                            C=CN                                                                            SO=S                                                                         50 S=SN                                                                            DO 60 J=1,N,N4                                                                  L0=J+N1                                                                         L2=L0+N3                                                                        L1=L2-N2                                                                        L3=L1+N3                                                                        P=A(L2)*S-A(L3)*C                                                               Q=A(L2)*C+A(L3)*S                                                               A(L2)=Q-A(L1)                                                                   A(L3)=Q+A(L1)                                                                   A(L1)=A(L0)-P                                                                60 A(L0)=A(L0)+P                                                                   N1=N2                                                                           N2=N3                                                                           N3=N4                                                                        70 N4=N4+N4                                                                        DO 80 J=2,N1                                                                    P=A(N2+J)                                                                       A(N2+J)=A(N+2-J)                                                             80 A(N+2-J)=P                                                                   90 A(1)=(A(1)+A(N2+1))*0.5                                                         A(N2+1)=A(1)-A(N2+1)                                                      C---------------------------------------------------------------------C           100 ILL=0                                                                           RETURN                                                                    C---------------------------------------------------------------------C           110 IF(M.EQ.0) GO TO 100                                                            ILL=30000                                                                       RETURN                                                                          END                                                                       C=====================================================================C         C     SUBROUTINE FFTRI PERFORMS DISCRETE FOURIER SYMTHESIS BY         C         C     RADIX-2 REAL FFT ALGORITHM                                      C         C     USAGE: CALL FFTRI(A,M,ILL)                                      C         C          A......1-DIMENSIONAL REAL ARRAY OF SIZE 2**M               C         C                 INPUT....DATA TO BE SYNTHESIZED                     C         C                          K-TH COSINE COMPONENT IN A(K+1)            C         C                          K-TH SINE COMPONENT IN A(N/2+K+1),N=2**M   C         C                 OUTPUT...SYNTHESIZED DATA                           C         C          M......INTEGER INPUT...BASE 2 LOGARITHM OF DATA SIZE       C         C          ILL....INTEGER OUTPUT..ERROR CODE 0: NORMAL TERMINATION    C         C                                            30000: PARAMETER ERROR   C         C     SLAVE ROUTINE: BITREV(NUMPAC) FOR BIT REVERSAL REARRANGEMENT    C         C     AUTHOR: I.NINOMIYA (CHUBU UNIVERSITY,KASUGAI,AICHI JAPAN 487)   C         C     DATA OF CREATION:  1981-04-01                                   C         C=====================================================================C         C---------------------------------------------------------------------C               SUBROUTINE FFTRI(A,M,ILL)                                                 C---------------------------------------------------------------------C               DIMENSION A(*)                                                                  DOUBLE PRECISION DC(32),DS(32),SS                                         C---------------------------------------------------------------------C         C     DC(I)=COS(PI/2**(I+1)),DS(I)=SIN(PI/2**(I+1))                             C---------------------------------------------------------------------C               DATA DC( 1)/ 0.707106781186547531D+00/                                          DATA DC( 2)/ 0.923879532511286752D+00/                                          DATA DC( 3)/ 0.980785280403230444D+00/                                          DATA DC( 4)/ 0.995184726672196887D+00/                                          DATA DC( 5)/ 0.998795456205172391D+00/                                          DATA DC( 6)/ 0.999698818696204222D+00/                                          DATA DC( 7)/ 0.999924701839144545D+00/                                          DATA DC( 8)/ 0.999981175282601137D+00/                                          DATA DC( 9)/ 0.999995293809576177D+00/                                          DATA DC(10)/ 0.999998823451701907D+00/                                          DATA DC(11)/ 0.999999705862882213D+00/                                          DATA DC(12)/ 0.999999926465717850D+00/                                          DATA DC(13)/ 0.999999981616429293D+00/                                          DATA DC(14)/ 0.999999995404107320D+00/                                          DATA DC(15)/ 0.999999998851026833D+00/                                          DATA DC(16)/ 0.999999999712756701D+00/                                          DATA DC(17)/ 0.999999999928189179D+00/                                          DATA DC(18)/ 0.999999999982047291D+00/                                          DATA DC(19)/ 0.999999999995511826D+00/                                          DATA DC(20)/ 0.999999999998877953D+00/                                          DATA DC(21)/ 0.999999999999719488D+00/                                          DATA DC(22)/ 0.999999999999929876D+00/                                          DATA DC(23)/ 0.999999999999982472D+00/                                          DATA DC(24)/ 0.999999999999995615D+00/                                          DATA DC(25)/ 0.999999999999998904D+00/                                          DATA DC(26)/ 0.999999999999999722D+00/                                          DATA DC(27)/ 0.999999999999999931D+00/                                          DATA DC(28)/ 0.999999999999999986D+00/                                          DATA DC(29)/ 0.100000000000000000D+01/                                          DATA DC(30)/ 0.100000000000000000D+01/                                          DATA DC(31)/ 0.100000000000000000D+01/                                          DATA DC(32)/ 0.100000000000000000D+01/                                          DATA DS( 1)/ 0.707106781186547531D+00/                                          DATA DS( 2)/ 0.382683432365089768D+00/                                          DATA DS( 3)/ 0.195090322016128262D+00/                                          DATA DS( 4)/ 0.980171403295606036D-01/                                          DATA DS( 5)/ 0.490676743274180141D-01/                                          DATA DS( 6)/ 0.245412285229122881D-01/                                          DATA DS( 7)/ 0.122715382857199263D-01/                                          DATA DS( 8)/ 0.613588464915447527D-02/                                          DATA DS( 9)/ 0.306795676296597625D-02/                                          DATA DS(10)/ 0.153398018628476561D-02/                                          DATA DS(11)/ 0.766990318742704540D-03/                                          DATA DS(12)/ 0.383495187571395563D-03/                                          DATA DS(13)/ 0.191747597310703308D-03/                                          DATA DS(14)/ 0.958737990959773447D-04/                                          DATA DS(15)/ 0.479368996030668847D-04/                                          DATA DS(16)/ 0.239684498084182193D-04/                                          DATA DS(17)/ 0.119842249050697064D-04/                                          DATA DS(18)/ 0.599211245264242774D-05/                                          DATA DS(19)/ 0.299605622633466084D-05/                                          DATA DS(20)/ 0.149802811316901114D-05/                                          DATA DS(21)/ 0.749014056584715715D-06/                                          DATA DS(22)/ 0.374507028292384129D-06/                                          DATA DS(23)/ 0.187253514146195347D-06/                                          DATA DS(24)/ 0.936267570730980836D-07/                                          DATA DS(25)/ 0.468133785365490931D-07/                                          DATA DS(26)/ 0.234066892682745532D-07/                                          DATA DS(27)/ 0.117033446341372770D-07/                                          DATA DS(28)/ 0.585167231706863850D-08/                                          DATA DS(29)/ 0.292583615853431935D-08/                                          DATA DS(30)/ 0.146291807926715968D-08/                                          DATA DS(31)/ 0.731459039633579864D-09/                                          DATA DS(32)/ 0.365729519816789906D-09/                                    C---------------------------------------------------------------------C               IF(M.LE.0) GO TO 100                                                            N=2**M                                                                          N4=N                                                                            N3=N/2                                                                          N2=N3/2                                                                         N1=N2/2                                                                         P=A(1)                                                                          A(1)=P+A(N3+1)                                                                  A(N3+1)=P-A(N3+1)                                                               IF(M.EQ.1) GOTO 90                                                              DO 20 J=2,N2                                                                    P=A(N3+J)                                                                       A(N3+J)=A(N+2-J)                                                             20 A(N+2-J)=P                                                                      DO 80 I=M-2,0,-1                                                                DO 40 L=1,N,N3                                                                  L1=L+N2                                                                         P=A(L)                                                                          A(L)=P+A(L1)                                                                 40 A(L1)=P-A(L1)                                                                   IF(N1.EQ.0) GO TO 90                                                            C=DC(I)                                                                         S=DS(I)                                                                         SS=DS(I)+DS(I)                                                                  CO=1.0                                                                          SO=0.0                                                                          DO 60 K=1,N1-1                                                                  N3K=N3-K                                                                        N2K=N2-K                                                                        DO 50 J=1,N,N4                                                                  L0=J+K                                                                          L2=L0+N3                                                                        L1=J+N3K                                                                        L3=L1+N3                                                                        P=A(L0)-A(L1)                                                                   Q=A(L2)+A(L3)                                                                   A(L0)=A(L0)+A(L1)                                                               A(L1)=A(L3)-A(L2)                                                               A(L2)=C*P+S*Q                                                                   A(L3)=C*Q-S*P                                                                   L1=L0+N2                                                                        L3=L1+N3                                                                        L0=J+N2K                                                                        L2=L0+N3                                                                        P=A(L0)-A(L1)                                                                   Q=A(L2)+A(L3)                                                                   A(L0)=A(L0)+A(L1)                                                               A(L1)=A(L3)-A(L2)                                                               A(L2)=S*P+C*Q                                                                   A(L3)=S*Q-C*P                                                                50 CONTINUE                                                                        CN=CO-SS*S                                                                      SN=SS*C+SO                                                                      CO=C                                                                            C=CN                                                                            SO=S                                                                         60 S=SN                                                                            DO 70 J=1,N,N4                                                                  L0=J+N1                                                                         L2=L0+N3                                                                        L1=L2-N2                                                                        L3=L1+N3                                                                        P=A(L0)-A(L1)                                                                   Q=A(L2)+A(L3)                                                                   A(L0)=A(L0)+A(L1)                                                               A(L1)=A(L3)-A(L2)                                                               A(L2)=P*S+Q*C                                                                70 A(L3)=Q*S-P*C                                                                   N4=N3                                                                           N3=N2                                                                           N2=N1                                                                        80 N1=N1/2                                                                   C---------------------------------------------------------------------C            90 CALL BITREV(A,M,ILL)                                                      C---------------------------------------------------------------------C               RETURN                                                                    C---------------------------------------------------------------------C           100 IF(M.LT.0) GO TO 110                                                            ILL=0                                                                           RETURN                                                                      110 ILL=30000                                                                       RETURN                                                                          END                                                                       C=====================================================================C         C     SUBROUTINE BITREV PERFORMS BIT REVERSAL REARRANGEMENT OF        C         C     REAL ARRAY OF SIZE OF THE FORM 2**L                             C         C     USAGE: CALL BITREV(A,L,ILL)                                     C         C          A......1-DIMENSIONAL REAL ARRAY OF SIZE 2**L               C         C                 INPUT....DATA TO BE REARRANGED                      C         C                 OUTPUT...REARRANGED DATA                            C         C          L......INTEGER INPUT...BASE 2 LOGARITHM OF DATA SIZE       C         C          ILL....INTEGER OUTPUT..ERROR CODE 0: NORMAL TERMINATION    C         C                                            30000: PARAMETER ERROR   C         C     AUTHOR: I.NINOMIYA (CHUBU UNIVERSITY,KASUGAI,AICHI JAPAN 487)   C         C     DATA OF CREATION:  1981-04-01                                   C         C=====================================================================C         C---------------------------------------------------------------------C               SUBROUTINE BITREV(A,L,ICON)                                               C---------------------------------------------------------------------C               DIMENSION A(*),ITEST(20),INC(20)                                          C-------- PREPARATION ------------------------------------------------C               IF(L.LE.0.OR.L.GT.23) GO TO 8000                                                NN=0                                                                            NR=0                                                                            I=L-1                                                                           M=2**I                                                                          K=2                                                                             IF(I-2) 60,30,10                                                             10 I=I-1                                                                           ITEST(I-1)=M-K                                                                  K=K+K                                                                           INC(I-1)=K-ITEST(I-1)                                                           IF(I-3) 30,10,10                                                          C-------- MAIN LOOP --------------------------------------------------C            20 NR=INC(I)+NR                                                                 30 MR=M+NR                                                                         IF(NR-NN) 50,50,40                                                           40 W=A(NN+1)                                                                       A(NN+1)=A(NR+1)                                                                 A(NR+1)=W                                                                       MN=M+NN                                                                         W=A(MN+2)                                                                       A(MN+2)=A(MR+2)                                                                 A(MR+2)=W                                                                    50 NN=NN+2                                                                         W=A(NN)                                                                         A(NN)=A(MR+1)                                                                   A(MR+1)=W                                                                       NR=K+NR                                                                      60 MR=M+NR                                                                         IF(NR-NN) 80,80,70                                                           70 W=A(NN+1)                                                                       A(NN+1)=A(NR+1)                                                                 A(NR+1)=W                                                                       MN=M+NN                                                                         W=A(MN+2)                                                                       A(MN+2)=A(MR+2)                                                                 A(MR+2)=W                                                                    80 NN=NN+2                                                                         W=A(NN)                                                                         A(NN)=A(MR+1)                                                                   A(MR+1)=W                                                                       I=1                                                                             IF(NN-M) 100,110,110                                                         90 I=I+1                                                                       100 IF(NR-ITEST(I)) 20,90,90                                                  C-------- EXIT -------------------------------------------------------C           110 ICON=0                                                                          RETURN                                                                    C-------- ERROR HANDLING ---------------------------------------------C          8000 ICON=30000                                                                      RETURN                                                                          END                                                                       